{"CoRequisites": [], "CreditType": "", "Credits": "3.00", "CrossListed": "N", "DepartmentID": "43", "Departments": "EN Applied Mathematics & Statistics", "Description": "Quantum computing uses quantum mechanical principles to process information in ways that can outperform classical computation for certain tasks. This course will provide an introduction to the mathematical theory of quantum computing. Topics include:
    • An introduction to the quantum information framework;
    • Several key quantum algorithms (including Shor’s factoring algorithm and Grover’s search algorithm)
    • Core ideas from Quantum information theory(including density matrices and quantum operations on them , distance measures between quantum states.)
If time allows, we will also introduce problems in quantum computing that can be studied using tools from algebraic graph theory such as quantum walks.", "Equivalencies": [], "EvaluationUrls": [], "Fees": [], "GradeSystemName": "AE Grad Letter", "InstructionMethods": "In-Person", "Instructors": [{"HopkinsID": "C1EA9D"}], "Meetings": [{"Building": "Bloomberg", "DOW": "TTh", "Dates": "08-31-2026 to 12-11-2026", "Format": "Lecture", "Times": "10:30 AM - 11:45 AM"}], "PosTags": [], "PrereqCoursesCatalogs": [], "Prerequisites": [], "Restrictions": [{"Description": "", "RestrictionName": "Grad students"}], "SampleSyllabus": "", "SectionCoReqNotes": "", "SectionCoRequisites": "", "StandardSyllabusLink": "", "TextbookInformations": [{"AttributeValue": "Follett", "BookstoreID": "2393", "ClassStartDate": "20260831", "CourseName": "EN.553.750", "CourseNumber": "750", "Department": "EN553", "IdrGroupTerm": "Fall 2026", "Location": "Homewood Campus", "MbsGroupDesignator": "", "MbsSiteCode": "", "Name": "01", "SectionNumber": "01", "Term": "Fall2026", "ZonesName": "ASEN - UGrad"}], "WebNotes": ""}

{"CoRequisites": [], "CreditType": "", "Credits": "4.00", "CrossListed": "Y", "DepartmentID": "43", "Departments": "EN Applied Mathematics & Statistics", "Description": "Introduction to the basic principles of mathematical statistics and data analysis. Emphasis on techniques of application. Classical parametric estimation, hypothesis testing, and multiple decision problems; linear models, analysis of variance, and regression; nonparametric and robust procedures; decision-theoretic setting, Bayesian methods. Recommended Course Background: EN.553.620 AND ( AS.110.201 OR AS.110.212 OR EN.553.291 ).", "Equivalencies": [], "EvaluationUrls": [], "Fees": [], "GradeSystemName": "AE Grad Letter", "InstructionMethods": "In-person", "Instructors": [{"HopkinsID": "1AAB5B|1AAB5B"}], "Meetings": [{"Building": "Bloomberg", "DOW": "MW", "Dates": "08-31-2026 to 12-11-2026", "Format": "Lecture", "Times": "01:30 PM - 02:45 PM"}, {"Building": "Maryland", "DOW": "T", "Dates": "08-31-2026 to 12-11-2026", "Format": "Discussion Section", "Times": "06:00 PM - 06:50 PM"}], "PosTags": [{"Tag": "BMED-BDS"}, {"Tag": "BMED-IMD"}], "PrereqCoursesCatalogs": [{"Description": "Introduction to mathematical statistics. Finite population sampling, approximation methods,classical parametric estimation, hypothesis testing, analysis of variance, and regression. Bayesian methods.", "Name": "EN.553.430", "SssCoursesId": 39356, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Mathematical Statistics"}, {"Description": "Probability and its applications, at the calculus level. Emphasis on techniques of application and on rigorous mathematical demonstration.  Probability, combinatorial probability, random variables, distribution functions, important probability distributions, independence, conditional probability, moments, covariance and correlation, limit theorems.  Students initiating graduate work in probability or statistics should enroll in EN.553.620 or EN.553.720.  Prerequisites: one year of calculus.  Corequisites: multivariable calculus and linear algebra.

Students who have received credit for AS.110.106 and/or AS.110.107 taken prior to Fall 2020 should contact the course instructor to determine whether they can receive permission to register for this course.", "Name": "EN.553.420", "SssCoursesId": 39352, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Probability"}, {"Description": "Probability and its applications, at the calculus level. Emphasis on techniques of application and on rigorous mathematical demonstration. Probability, combinatorial probability, random variables, distribution functions, important probability distributions, independence, conditional probability, moments, exchangeability, joint distributions, conditional distributions and expectation, covariance and correlation, limit theorems.  The honors version of this course will have enrichment exercises that explore and extend ideas learned in the ordinary lecture.  Students initiating graduate work in probability or statistics should enroll in EN.550.620. Auditors are not permitted. Recommended Course Background: one year of calculus and mathematical maturity; Co-requisite: multivariable calculus. 
By permission of the instructor or by recommendation of an AMS faculty member.", "Name": "EN.553.421", "SssCoursesId": 44541, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Honors Probability"}, {"Description": "Probability and its applications, at the calculus level. Emphasis on techniques of application and on rigorous mathematical demonstration. Probability, combinatorial probability, random variables, distribution functions, important probability distributions, independence, conditional probability, moments, covariance and correlation, limit theorems.  Recommended course background: (AS.110.109 or  AS.110.113) and previously or concurrently (AS.110.202 or AS.110.201 or AS.110.212).", "Name": "EN.553.620", "SssCoursesId": 39380, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Probability"}], "Prerequisites": [{"Description": "Students may receive credit for EN.553.430 or EN.553.630, but not both.", "Expression": "EN.553.430[C]", "IsNegative": "Y"}, {"Description": "Students must have completed EN.553.420 OR EN.553.421 OR EN.553.620 prior to enrolling in EN.553.630.", "Expression": "EN.553.420[C]^OR^EN.553.421[C]^OR^EN.553.620[C]", "IsNegative": "N"}], "Restrictions": [{"Description": "", "RestrictionName": "Grad students"}], "SampleSyllabus": "", "SectionCoReqNotes": "", "SectionCoRequisites": "", "StandardSyllabusLink": "", "TextbookInformations": [{"AttributeValue": "Follett", "BookstoreID": "2393", "ClassStartDate": "20260831", "CourseName": "EN.553.630", "CourseNumber": "630", "Department": "EN553", "IdrGroupTerm": "Fall 2026", "Location": "Homewood Campus", "MbsGroupDesignator": "", "MbsSiteCode": "", "Name": "01", "SectionNumber": "01", "Term": "Fall2026", "ZonesName": "ASEN - UGrad"}], "WebNotes": "Registration restricted to Applied Mathematics and Statistics Department graduate students only for two weeks after the start of registration.  Some seats may be reserved for incoming departmental students until the end of summer. First enrollment preference in seats held for incoming students is given to AMS department students and MSEM Probability&Statistics and Operations Research areas of focus students. If space permits, all other students who register will need departmental permission to remain enrolled in the course."}

