{"CoRequisites": [], "CreditType": "", "Credits": "4.00", "CrossListed": "N", "DepartmentID": "43", "Departments": "EN Applied Mathematics & Statistics", "Description": "Introduction to the mathematics of finite systems. Logic; Boolean algebra; induction and recursion; sets, functions, relations, equivalence, and partially ordered sets; elementary combinatorics; modular arithmetic and the Euclidean algorithm; polynomials rings, group theory; permutations groups and Galois theory; graph theory. Selected applications. The concept of a proof and development of the ability to recognize and construct proofs and analyze algorithms are part of the course. Recommended Course Background: Four years of high school mathematics.", "Equivalencies": [], "EvaluationUrls": [], "Fees": [], "GradeSystemName": "AE Ugrad Letter", "InstructionMethods": "In-person", "Instructors": [{"HopkinsID": "ABBDCD|ABBDCD"}], "Meetings": [{"Building": "Maryland", "DOW": "MWF", "Dates": "08-31-2026 to 12-11-2026", "Format": "Lecture", "Times": "10:00 AM - 10:50 AM"}, {"Building": "Hodson", "DOW": "Th", "Dates": "08-31-2026 to 12-11-2026", "Format": "Discussion Section", "Times": "06:00 PM - 06:50 PM"}], "PosTags": [], "PrereqCoursesCatalogs": [{"Description": "Introduction to the mathematics of finite systems. Logic; Boolean algebra; induction and recursion; sets, functions, relations, equivalence, and partially ordered sets; elementary combinatorics; modular arithmetic and the Euclidean algorithm; group theory; permutations and symmetry groups; graph theory. Selected applications. The concept of a proof and development of the ability to recognize and construct proofs are part of the course. Recommended Course Background: Four years of high school mathematics.", "Name": "EN.553.171", "SssCoursesId": 39339, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Discrete Mathematics"}, {"Description": "This course provides an introduction to mathematical reasoning and discrete structures relevant to computer science. Topics include propositional and predicate logic, proof techniques including mathematical induction, sets, relations, functions, recurrences, counting techniques, simple computational models, asymptotic analysis, discrete probability, graphs, trees, and number theory.", "Name": "EN.601.230", "SssCoursesId": 44204, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Mathematical Foundations for Computer Science"}, {"Description": "Counting techniques: generating functions, recurrence relations, Polya’s theorem. Combinatorial designs: Latin squares, finite geometries, balanced incomplete block designs. Emphasis on problem solving. Recommended Course Background: AS.553.291 or AS.110.201

Students who have received credit for AS.110.106 and/or AS.110.107 taken prior to Fall 2020 should contact the course instructor to determine whether they can receive permission to register for this course.", "Name": "EN.553.471", "SssCoursesId": 39348, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Combinatorial Analysis"}, {"Description": "Study of systems of “vertices” with some pairs joined by “edges.” Theory of adjacency, connectivity, traversability, feedback, and other concepts underlying properties important in engineering and the sciences. Topics include paths, cycles, and trees; routing problems associated with Euler and Hamilton; design of graphs realizing specified incidence conditions and other constraints. Attention directed toward problem solving, algorithms, and applications. One or more topics taken up in greater depth.", "Name": "EN.553.472", "SssCoursesId": 39616, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Graph Theory"}, {"Description": "An introduction to combinatorial analysis at the graduate level. Meets concurrently with 553.471. Counting techniques: generating functions, recurrence relations, Polya’s theorem. Combinatorial designs: Latin squares, finite geometries, balanced incomplete block designs. Emphasis on problem solving. Recommended Course Background: EN.553.291 or AS.110.201", "Name": "EN.553.671", "SssCoursesId": 39789, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Combinatorial Analysis"}, {"Description": "Study of systems of “vertices” with some pairs joined by “edges.” Theory of adjacency, connectivity, traversability, feedback, and other concepts underlying properties important in engineering and the sciences. Topics include paths, cycles, and trees; routing problems associated with Euler and Hamilton; design of graphs realizing specified incidence conditions and other constraints. Attention directed toward problem solving, algorithms, and applications. One or more topics taken up in greater depth. Recommended Course Background: (EN.553.291 OR AS.110.201 OR AS.110.212)", "Name": "EN.553.672", "SssCoursesId": 39627, "StatusName": "Active", "TermName": "AE Fall 2026", "Title": "Graph Theory"}], "Prerequisites": [{"Description": "Students may only earn credit for one of the following: EN.553.171, EN.553.172, OR EN.601.230.
EN.553.172 may not be taken after EN.553.471 OR EN.553.472 OR EN.553.671 OR EN.553.672.", "Expression": "EN.553.171[C]^OR^EN.601.230[C]^OR^EN.553.471[C]^OR^EN.553.472[C]^OR^EN.553.671[C]^OR^EN.553.672[C]", "IsNegative": "Y"}], "Restrictions": [{"Description": "", "RestrictionName": "UGrad Applied Mathematics and Statistics majors"}], "SampleSyllabus": "", "SectionCoReqNotes": "", "SectionCoRequisites": "", "StandardSyllabusLink": "", "TextbookInformations": [{"AttributeValue": "Follett", "BookstoreID": "2393", "ClassStartDate": "20260831", "CourseName": "EN.553.172", "CourseNumber": "172", "Department": "EN553", "IdrGroupTerm": "Fall 2026", "Location": "Homewood Campus", "MbsGroupDesignator": "", "MbsSiteCode": "", "Name": "02", "SectionNumber": "02", "Term": "Fall2026", "ZonesName": "ASEN - UGrad"}], "WebNotes": ""}

